window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2024>1","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Which of the following land tenure systems allows a farmer to cultivate a piece of land in one growing season,at a fee?","images":[],"options":{"A":"Freehold","B":"Communal","C":"Rent","D":"Leasehold"},"answer":"C","explanation":"Rent: Under this system, a farmer pays a fee to use the land for a specified period, which can be as short as one growing season. This arrangement is temporary and based on the payment of rent.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>2","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"BASIC CONCEPTS : ROLES OF GOVERNMENT IN AGRICULTURAL DEVELOPMENT","question":"Agriculture could be made attractive to young people in West Africa through the","images":[],"options":{"A":"fabrication of simple farm tools in a locality","B":"provision of basic amenities in rural areas","C":"cultivation of locally available seeds","D":"provision of compost to farmers"},"answer":"B","explanation":"Provision of basic amenities in rural areas: Providing amenities such as electricity, clean water, healthcare, schools, internet access, and recreational facilities makes rural living more comfortable and attractive. This can significantly influence young people's willingness to engage in agricultural activities because they won't have to sacrifice their quality of life to work in agriculture.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>3","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"BASIC CONCEPTS : ROLES OF GOVERNMENT IN AGRICULTURAL DEVELOPMENT","question":"Which of the following agricultural programmes was mainly established to provide agricultural extension services?","images":[],"options":{"A":"Green Revolution","B":"Operation Feed the Nation","C":"River Basin Development Authority","D":"Agricultural Development Project"},"answer":"D","explanation":"Agricultural Development Project (ADP):    The primary focus of the Agricultural Development Project (ADP) is to enhance agricultural productivity and rural development through the provision of comprehensive agricultural extension services.  ADPs are designed to support farmers by offering technical advice, training, and access to improved farming techniques and inputs.  The goal is to improve farming practices, increase crop yields, and ultimately improve the livelihoods of rural farmers.  These projects often include components such as infrastructure development, marketing support, and access to credit, but the core emphasis remains on delivering effective extension services to farmers.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>4","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"The following tools are used in nursery operations except","images":[],"options":{"A":"secateurs","B":"sickle","C":"shears","D":"dibber"},"answer":"B","explanation":"A sickle is a tool with a curved blade used for harvesting crops or cutting grass. It is not typically used in nursery operations, which involve the care and cultivation of young plants rather than harvesting.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>5","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"A major difference between disc harrow and disc plough is that","images":[],"options":{"A":"disc plough has more discs than disc harrow","B":"discs in disc plough are spaced far apart than in disc harrow.","C":"disc plough has two pairs of gangs while disc harrow has one pair of gangs","D":"disc plough has smaller discs than disc harrow"},"answer":"B","explanation":"The discs in disc plough are spaced farther apart to allow for deeper penetration and to handle larger volumes of soil, debris, and crop residue while the discs in a disc harrow are placed closer together and are designed for secondary tillage.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>6","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrates a source of farm power.Use it to answer the question      An advantage of using the power generated from the illustrated diagram is that it","images":["data:image/png;base64,"],"options":{"A":"could be stored for future use","B":"is easy to control","C":"could be used for all farm operations","D":"is available everywhere"},"answer":"A","explanation":"It could be stored for future use: Wind power can be converted into electricity and stored in batteries or other energy storage systems. This stored energy can then be used when wind speeds are low, ensuring a consistent power supply.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>7","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrates a source of farm power.Use it to answer the question    The power generated from the illustrated diagram could be converted to","images":["data:image/png;base64,"],"options":{"A":"solar energy","B":"electrical energy","C":"hydro power","D":"animal power"},"answer":"B","explanation":"Wind power is harnessed by wind turbines, which convert the kinetic energy of the wind into electrical energy. This electricity can then be used directly, stored in batteries, or fed into the power grid for various applications.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>8","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Gunter's chain is used for","images":[],"options":{"A":"determining depth of soil moisture","B":"measuring slope of farmland","C":"measuring distances","D":"restraining bulls"},"answer":"C","explanation":"Gunter's chain: It is a measuring device used for land surveying. The chain is 66 feet long and consists of 100 links, each 7.92 inches long. It was widely used in surveying to measure distances and calculate areas of land.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>9","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The chemical composition of soil is influenced by its","images":[],"options":{"A":"pH","B":"structure","C":"parent material","D":"living organisms"},"answer":"C","explanation":"Parent material: This is the original rock or organic material from which the soil develops. The minerals and elements present in the parent material directly influence the soil's chemical composition as it weathers and breaks down. Different parent materials will contribute different minerals and nutrients to the soil.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>10","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The ash produced after burning crop residues would","images":[],"options":{"A":"decrease soil acidity","B":"increase soil acidity","C":"decrease soil alkalinity","D":"render the pH unchanged"},"answer":"A","explanation":"Decrease soil acidity: Ash from burnt plant material is typically alkaline, containing minerals such as calcium, potassium, and magnesium. When applied to soil, it can raise the pH, thus decreasing soil acidity.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>11","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"A soil sample that contains predominantly mineral matter that are smaller than 0.002 mm in size is","images":[],"options":{"A":"gravel","B":"sand","C":"clay","D":"loam"},"answer":"C","explanation":"Clay: Clay particles are defined as being smaller than 0.002 mm in diameter. They are the finest soil particles and are known for their ability to retain water and nutrients.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>12","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"The diagram below illustrates a bag of compound fertilizer. Use it to answer the question      The least nutrient in the illustrated bag of fertilizer is","images":["data:image/png;base64,"],"options":{"A":"potassium","B":"sulphur","C":"phosphorus","D":"nitrogen"},"answer":"C","explanation":"Net weight = 50kg  Compound fertilizer contains N:P:K(Nitrogen:Phosphorus:Potassium)=10:5:15  10 + 5 + 15=30  Nitrogen = 10/30 x 50 =16.67kg  Phosphorus = 5/30 x 50 =8.33kg  Potassium = 15/30 x 50 =25kg  The least nutrient in the illustrated bag of fertilizer is Phosphorus","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>13","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"The diagram below illustrates a bag of compound fertilizer. Use it to answer the question    Determine the quantity of potassium in the illustrated bag of fertilizer","images":["data:image/png;base64,"],"options":{"A":"8.3kg","B":"16.7kg","C":"25.0kg","D":"30.0kg"},"answer":"C","explanation":"Net weight = 50kg  Compound fertilizer contains N:P:K(Nitrogen:Phosphorus:Potassium)=10:5:15  10 + 5 + 15=30  Potassium = 15/30 x 50 =25kg","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2024>14","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The plant nutrient which is responsible for the green colour of leaves is","images":[],"options":{"A":"boron","B":"magnesium","C":"calcium","D":"potassium"},"answer":"B","explanation":"Magnesium: This nutrient is a central component of chlorophyll, the pigment responsible for the green color in leaves. Chlorophyll is essential for photosynthesis, the process by which plants make food.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>15","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"In order to check erosion on a sloping land,farmers are advised to make","images":[],"options":{"A":"ridges across the slope","B":"furrows across the contours","C":"ridges along the slope","D":"ditches along water channels"},"answer":"A","explanation":"Ridges across the slope: Creating ridges perpendicular to the slope helps to slow down water runoff and reduce soil erosion. This technique, known as contour farming, helps to trap water and allows it to infiltrate the soil, reducing the speed of erosion","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>16","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The diagram below illustrates the root system of a crop. Use it to answer the question      An example of a crop with the illustrated root system is","images":["data:image/png;base64,"],"options":{"A":"rice","B":"tomato","C":"oil palm","D":"soya bean"},"answer":"D","explanation":"Root Nodules: The root nodules are visible swellings on the roots of the soybean plant. They vary in size and shape but are typically round or oval. These nodules are the sites where the rhizobia bacteria convert nitrogen from the atmosphere into a form usable by the plant.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>17","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The diagram below illustrates the root system of a crop. Use it to answer the question    A bacterium that could be found in the part labelled I is","images":["data:image/png;base64,"],"options":{"A":"Nitrosomonas","B":"Nitrobacter","C":"Azotobacter","D":"Rhizobium"},"answer":"D","explanation":"Rhizobium: This bacterium forms a symbiotic relationship with leguminous plants like soybeans. It colonizes the root nodules and fixes atmospheric nitrogen into a form that the plant can use for growth. This process enriches the soil with nitrogen and is crucial for the health of the soybean plant.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>18","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The diagram below illustrates the root system of a crop. Use it to answer the question    Which of the following fertilizers would not be required by a crop with the illustrated root system?","images":["data:image/png;base64,"],"options":{"A":"Potassium sulphate","B":"Ammonium nitrate","C":"Rock phosphate","D":"Magnesium sulphate"},"answer":"C","explanation":"Rock phosphate: Phosphate is essential for root development and energy transfer in plants, but the primary phosphorus source for soybeans is typically provided by the phosphorus already available in the soil or through fertilizers specifically designed to provide phosphorus. Rock phosphate is not as readily available to plants as other phosphorus fertilizers, and soybeans can often meet their phosphorus needs from other sources.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>19","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"An important limitation in the use of sprinkler irrigation system is that","images":[],"options":{"A":"soluble fertilizers and herbicides cannot be applied with irrigation water","B":"it cannot be used on farmlands with high evapo-transpiration rates","C":"it requires the use of large volume of water","D":"high wind velocity could prevent uniform distribution of irrigation water"},"answer":"D","explanation":"High wind velocity could prevent uniform distribution of irrigation water: High winds can cause the water to be blown off course, resulting in uneven distribution and potentially leading to over-watering in some areas and under-watering in others. This can reduce the effectiveness of the irrigation system and may lead to inefficiencies in water use.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>20","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Which of the following characteristics is not associated with monocotyledonous crops?","images":[],"options":{"A":"Fibrous root system","B":"Parallel venation of leaf","C":"Leaves are net-veined","D":"Presence of one-seed leaf"},"answer":"C","explanation":"Leaves are net-veined: This characteristic is associated with dicotyledonous (dicot) plants, not monocots. In dicots, leaves have a network or \"net-like\" pattern of veins.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>21","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"A crop that could be grown to serve as shade in a young cocoa plantation is","images":[],"options":{"A":"maize","B":"cowpea","C":"cassava","D":"banana"},"answer":"D","explanation":"Banana: Banana plants can provide effective shade for young cocoa plants. They grow relatively tall and have large leaves that can help shield cocoa trees from excessive sunlight. This shading is beneficial for young cocoa plants as it helps protect them from direct sun and reduces soil moisture evaporation.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>22","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Molasses is a major by-product obtained from the processing of","images":[],"options":{"A":"pineapple","B":"cassava","C":"sugarcane","D":"sorghum"},"answer":"C","explanation":"Sugarcane: Molasses is a thick, dark syrup that is produced during the extraction of sugar from sugarcane. After sugarcane juice is extracted and crystallized to produce sugar, the remaining liquid is molasses. It is a by-product of the sugar refining process.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>23","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"The diagram below illustrates a storage structure for crops. Use it to answer the question      Which of the following crops are best preserved in the illustrated storage structure?","images":["data:image/png;base64,"],"options":{"A":"Groundnut pods","B":"Yam tubers","C":"Maize cobs","D":"Cocoa beans"},"answer":"C","explanation":"The storage structure shown in the diagram is a traditional granary or crib, often used in many parts of the world for storing cereals like maize. Key features of this type of storage include:    Elevation: The structure is elevated on stilts, which helps to protect the stored crops from pests and rodents. It also facilitates airflow around the stored crops, which is crucial for drying and preventing mold and rot.    Ventilation: The sides of the structure are designed to allow airflow, which helps to keep the stored maize cobs dry and reduces the risk of moisture buildup and subsequent spoilage.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>24","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"The diagram below illustrates a storage structure for crops. Use it to answer the question    The function of the part labelled I is to","images":["data:image/png;base64,"],"options":{"A":"promote adequate ventilation","B":"prevent infestation by insects","C":"protect from excessive rainfall","D":"prevent attack by rodents"},"answer":"D","explanation":"Prevent attack by rodents: The primary purpose of elevating the storage structure on stilts is to protect the stored crops from rodents. By raising the storage off the ground, it becomes more difficult for rodents to access the crops.    Therefore, the correct answer is that the function of the part labelled I is to prevent attack by rodents.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>25","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"The diagram below illustrates a storage structure for crops. Use it to answer the question    Which of the following environmental conditions would cause spoilage of crops stored in the illustrated structure?","images":["data:image/png;base64,"],"options":{"A":"High temperature and low relative humidity","B":"Low temperature and high relative humidity","C":"High rainfall and high wind velocity","D":"Low rainfall and low wind velocity"},"answer":"B","explanation":"Low temperature and high relative humidity: These conditions are problematic for crop storage. High relative humidity can lead to moisture buildup, which promotes mold and fungal growth, and low temperatures can slow down the drying process, exacerbating the problem of excess moisture. This combination is particularly conducive to spoilage in stored crops.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>26","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The correct sequence of land preparation for the cultivation of yam is","images":[],"options":{"A":"clearing\u2192stumping\u2192ploughing\u2192harrowing\u2192ridging","B":"ploughing\u2192clearing\u2192harrowing\u2192ridging\u2192stumping","C":"clearing \u2192harrowing \u2192ploughing\u2192stumping\u2192ridging","D":"ploughing\u2192stumping\u2192clearing\u2192ridging\u2192harrowing"},"answer":"A","explanation":"Clearing: This is the first step, which involves removing vegetation, trees, and other debris from the land to prepare it for farming.    Stumping: After clearing, any remaining tree stumps and roots are removed. This is important to ensure the land is free from obstacles that could interfere with ploughing and planting.    Ploughing: The soil is then ploughed to break it up and turn it over, which helps to aerate the soil and incorporate organic matter.    Harrowing: Following ploughing, harrowing is done to further break down soil clods and create a finer soil texture. This step also helps to level the soil surface.    Ridging: Finally, ridges are made. Yams are typically planted on ridges or mounds to improve drainage and ease of harvesting.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>27","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Tenera is a cultivated variety of oil palm with a","images":[],"options":{"A":"thin mesocarp, thick endocarp and a large kernel.","B":"thick mesocarp, thin endocarp and a moderate sized kernel.","C":"thick mesocarp, absence of endocarp and a small kernel","D":"thin mesocarp, thin endocarp and a moderate sized kernel"},"answer":"B","explanation":"Thick mesocarp: The mesocarp is the fleshy part of the fruit that contains the oil. Tenera palms are known for having a thick mesocarp, which is advantageous because it increases the oil yield.    Thin endocarp: The endocarp is the hard shell surrounding the kernel. Tenera palms have a thin endocarp, which makes it easier to extract the kernel and oil.    Moderate-sized kernel: The kernel is the seed inside the fruit, which also contains oil. Tenera palms typically have a moderate-sized kernel that contributes to the overall oil yield but is not overly large, balancing the oil content from both the mesocarp and kernel.    Tenera is a hybrid variety developed by crossing the Dura (thick endocarp and large kernel) and Pisifera (thin mesocarp and small kernel) varieties, resulting in the desirable characteristics of a thick mesocarp for high oil yield and a thin endocarp for easier processing.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2024>28","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"Use the information below to answer the question.  A farmer produced 25 tonnes of cocoa. If 16 bags of cocoa weigh one tonne and the cocoa was later sold at N350.00 per kilogramme.  (1 tonne = 1,000 kg)    Determine the income realised by the farmer","images":[],"options":{"A":"\u20a6140,000.00","B":"\u20a6400,000.00","C":"\u20a65,600,000.00","D":"\u20a68,750,000.00"},"answer":"D","explanation":"Convert tonnes to kilograms:    1tonne=1,000kg  1\u00a0tonne=1,000\u00a0kg  So,  25\u00a0tonnes=25\u00d71,000=25,000\u00a0kg  Calculate the income:  Income=Total\u00a0weight\u00a0in\u00a0kg\u00d7Price\u00a0per\u00a0kg  Income=25,000kg\u00d7\u20a6350/kg=\u20a68,750,000.00","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2024>29","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"Use the information below to answer the question.  A farmer produced 25 tonnes of cocoa. If 16 bags of cocoa weigh one tonne and the cocoa was later sold at N350.00 per kilogramme.  (1 tonne = 1,000 kg)  Calculate the cost of one bag of cocoa","images":[],"options":{"A":"\u20a662.50","B":"\u20a65,600.00","C":"\u20a68,750.00","D":"\u20a621,875.00"},"answer":"D","explanation":"Determine the weight of one bag of cocoa:    We know that 16 bags of cocoa weigh one tonne (1,000 kg).  Therefore, the weight of one bag of cocoa is:  1000kg/16 bags=62.5kg/bag  Determine the cost of one bag of cocoa:  The price per kilogram is \u20a6350.00.  So, the cost of one bag of cocoa is:  62.5\u00a0kg/bag\u00d7\u20a6350/kg=\u20a621,875.00  Therefore, the cost of one bag of cocoa is \u20a621,875.00.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>30","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"A disadvantage of selection as a method of crop improvement is that it","images":[],"options":{"A":"ensures the picking of crops with undesirable traits","B":"requires expertise when carrying it out","C":"increases the spread of diseases","D":"increases the susceptibility of crops to pests"},"answer":"B","explanation":"Requires expertise when carrying it out: Selection involves choosing the best plants based on specific desirable traits. This process requires a good understanding of genetics, plant breeding, and agronomy to be effective. Expertise is necessary to identify the best traits, avoid inbreeding, and manage other genetic complexities.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>31","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"Natural regeneration of forests may lead to","images":[],"options":{"A":"destruction of existing forest trees","B":"disruption of ecological balance","C":"lack of uniformity in growth of trees","D":"desert encroachment in arid regions"},"answer":"C","explanation":"Lack of uniformity in growth of trees: Natural regeneration involves the spontaneous regrowth of trees and vegetation without human intervention. This process often results in a forest with a diverse mix of tree species, ages, and sizes, leading to a lack of uniformity. The variation in conditions like light, soil, and water availability causes trees to grow at different rates and heights.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>32","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The diagram below illustrates the damage on a leaf caused by an insect pest of crops. Use it to answer the question      The damage to the illustrated leaf is most likely caused by","images":["data:image/png;base64,"],"options":{"A":"whitefly","B":"beetle","C":"grasshopper","D":"mealybug"},"answer":"C","explanation":"Grasshopper: Grasshoppers are known for chewing on the edges and surfaces of leaves, often creating irregular holes and ragged edges, which matches the damage shown in the diagram.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>33","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The diagram below illustrates the damage on a leaf caused by an insect pest of crops. Use it to answer the question    The biological process that would mostly be affected in the leaf is","images":["data:image/png;base64,"],"options":{"A":"transpiration","B":"respiration","C":"irritability","D":"photosynthesis"},"answer":"D","explanation":"Photosynthesis: This process involves the conversion of light energy into chemical energy by the chlorophyll in the leaves. The leaf damage, which includes significant portions of the leaf being eaten away, reduces the leaf area available for capturing sunlight and conducting photosynthesis. This directly impacts the plant's ability to produce food and energy.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>34","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The yield of oil palm could be reduced by infestation of","images":[],"options":{"A":"caterpillar","B":"myrid","C":"army worm","D":"cotton stainer"},"answer":"B","explanation":"Myrid: Myrids, particularly the species Sago palm leafhopper (Saltus alternans), are known pests of oil palm. They can cause significant damage by feeding on the sap of the palm, which can lead to reduced vigor and yield of the plant. The damage caused by myrids can result in the formation of sooty mold, which further impairs the plant's photosynthetic ability and overall health.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>35","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Breeds of sheep common in West Africa include","images":[],"options":{"A":"Sahel and Kano Brown","B":"Ouda and Yankasa","C":"Sokoto Red and Angora","D":"N\u00fabian and Kano Brown"},"answer":"B","explanation":"Ouda and Yankasa: These are well-known sheep breeds in West Africa. Ouda is a large, hardy breed, and Yankasa is a popular breed known for its good meat quality and adaptability to various environments in the region.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>36","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Low relative humidity in livestock pens would","images":[],"options":{"A":"predispose animals to diseases","B":"encourage mouldiness of feed","C":"decrease water intake","D":"increase water intake"},"answer":"D","explanation":"Increase water intake: In low humidity environments, the air is dry, which can cause animals to lose more moisture through respiration and sweating (in the case of animals that sweat). To compensate for this increased moisture loss, animals will drink more water to stay hydrated.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>37","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"A poultry farmer collects 100 trays of eggs per day on the farm. If the market price of a tray of eggs is \u20a6900.00, determine the income realised from the sale of eggs in one week.","images":[],"options":{"A":"\u20a6630,000.00","B":"\u20a690,000.00","C":"\u20a69,000.00","D":"\u20a66,300.00"},"answer":"A","explanation":"Calculate the daily income:    The farmer collects 100 trays of eggs per day.  The market price of one tray of eggs is \u20a6900.00.  Therefore, the daily income is:  100\u00a0trays/day\u00d7\u20a6900/tray=\u20a690,000.00/day  Calculate the weekly income:  There are 7 days in a week.  Therefore, the weekly income is:  \u20a690,000.00/day\u00d77\u00a0days/week=\u20a6630,000.00/week","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>38","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Which of the following statements is an advantage of pen mating?","images":[],"options":{"A":"The spread of venereal diseases is common","B":"Deformed males may not be able to mate","C":"The cost of keeping a breeding male is low","D":"The tendency of mating females on heat is high"},"answer":"D","explanation":"The tendency of mating females on heat is high: This is an advantage of pen mating. In pen mating, a breeding male is kept with a group of females, allowing natural mating behavior. This increases the likelihood that females will be mated when they are in heat because the male is constantly present and can detect when each female is ready to mate.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>39","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Pail feeding is commonly practised in the management of","images":[],"options":{"A":"pigs","B":"poultry","C":"cattle","D":"rabbits"},"answer":"C","explanation":"Cattle: Pail feeding is commonly used in the management of calves. This method is often employed to provide milk or milk replacer to young calves that are not yet able to graze or consume solid feed.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>40","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"The diagram below illustrates a management practice in poultry production. Use it to answer the question      The management practice illustrated in the diagram is","images":["data:image/png;base64,"],"options":{"A":"incubation","B":"hatching","C":"brooding","D":"candling"},"answer":"C","explanation":"Brooding: This is the process of providing supplemental heat and care to young chicks after they have hatched until they are able to regulate their own body temperature. The heat source shown in the diagram is used to keep the chicks warm during this critical period.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>41","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"The diagram below illustrates a management practice in poultry production. Use it to answer the question    Climatic factors that should be monitored during the management practice illustrated are  I. temperature  II. daylength  III. relative humidity","images":["data:image/png;base64,"],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I,II and III"},"answer":"B","explanation":"Temperature: Temperature is crucial in brooding as young chicks cannot regulate their body temperature effectively. Maintaining the appropriate temperature is essential for their growth and survival.  Relative Humidity: Relative humidity is also important as it can affect the chicks' comfort and health. Proper humidity levels help prevent dehydration and respiratory problems.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2024>42","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"The diagram below illustrates a management practice in poultry production. Use it to answer the question    The illustrated management practice is usually carried out in chicks from day old to","images":["data:image/png;base64,"],"options":{"A":"2 weeks","B":"4 weeks","C":"6 weeks","D":"8 weeks"},"answer":"B","explanation":"Brooding is the management practice of providing warmth and care to newly hatched chicks to ensure their proper growth and development. This practice is crucial during the early stages of a chick's life because they are unable to regulate their own body temperature effectively.    The brooding period typically lasts from day old up to 4 weeks of age. During this time, the chicks need a controlled environment to maintain their body temperature and ensure their health and growth.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>43","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"The meat from a tender calf is","images":[],"options":{"A":"beef","B":"mutton","C":"veal","D":"chevon"},"answer":"C","explanation":"Veal is the meat of young cattle, usually less than 3 months old. It is known for its tenderness and light color compared to beef, which comes from older cattle. Mutton is meat from mature sheep, and chevon is meat from goats.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>44","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following groups of diseases of farm animals are caused by bacteria?","images":[],"options":{"A":"Rinderpest, swine fever and trypanosomiasis","B":"Coccidiosis, Newcastle and fowl typhoid","C":"Fowl pox, mastitis and Gumboro","D":"Brucellosis, anthrax and tuberculosis"},"answer":"D","explanation":"Brucellosis is caused by bacteria of the genus  Brucella .  Anthrax is caused by  Bacillus anthracis .  Tuberculosis is caused by  Mycobacterium tuberculosis .","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>45","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"If an animal is likely to succumb to the effects of a pathogen, the animal is said to be","images":[],"options":{"A":"tolerant","B":"resistant","C":"susceptible","D":"immune"},"answer":"C","explanation":"Susceptibility refers to the vulnerability of an animal to infections or diseases. A susceptible animal is one that is more likely to be affected by a pathogen due to a lack of resistance or immune response. On the other hand, a resistant animal can withstand or fend off infections more effectively, and an immune animal has developed immunity to the pathogen. Tolerance refers to an animal's ability to endure or manage the effects of a disease without necessarily being immune to it.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>46","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Which of the following factors of production are affected by the law of diminishing returns?  I. Land  II. Labour  III. Capital","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I,II and III"},"answer":"C","explanation":"Labour (II) and Capital (III) are directly affected by the law of diminishing returns. As more units of labor or capital are added, while keeping other factors constant, their incremental contribution to production will eventually decline.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>47","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Which of the following changes would cause the demand curve to shift to the right?","images":[],"options":{"A":"A reduction in the size of the population","B":"An increase in income of the consumer","C":"Availability of close substitutes","D":"A decrease in the price of goods"},"answer":"B","explanation":"An increase in income of the consumer generally leads to an increase in demand for goods and services, shifting the demand curve to the right, as consumers have more purchasing power.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2024>48","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"The function of a farm manager is to","images":[],"options":{"A":"make agricultural policies for the government","B":"allocate available resources on the farm effectively","C":"execute agricultural extension programmes","D":"stabilise the prices of farm produce"},"answer":"B","explanation":"A farm manager's primary role involves overseeing the day-to-day operations of a farm, including making decisions on the allocation of resources such as labour, land, and capital to maximize productivity and profitability. This involves planning, organizing, and controlling various farm activities.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2024>49","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : BASIC ECONOMIC PRINCIPLES","question":"Marginal cost could be described as the","images":[],"options":{"A":"change in total cost as output is increased by one unit","B":"product of average variable cost and the number of units produced","C":"increase in fixed cost that results from increasing production by one unit.","D":"average physical product multiplied by the variable cost"},"answer":"A","explanation":"Marginal cost refers to the additional cost incurred when producing one more unit of output. It is calculated by finding the difference in total cost when output increases by one unit.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2024>50","subject":"Agricultural Science","year":"2024","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"Farm gate price is mostly enjoyed by","images":[],"options":{"A":"wholesalers","B":"producers","C":"consumers","D":"retailers"},"answer":"B","explanation":"The farm gate price is the price that producers (farmers) receive for their products when they sell them directly at the farm gate or at the point of sale before any further processing or distribution. This price is typically lower than the retail price because it excludes additional costs related to transportation, handling, and retailer markups.","marks":"1","difficulty":"1"}];